'use client';

import type { ComponentRef } from 'react';
import { forwardRef } from 'react';
import { useComponentConfig } from '../config-provider/context';
import SliderUI from './SliderUI';
import type SliderRoot from './SliderRoot';
import type { SliderProps } from './types';

const Slider = forwardRef<ComponentRef<typeof SliderRoot>, SliderProps>((props, ref) => {
  const config = useComponentConfig('slider');

  const mergedProps = {
    ...config,
    ...props
  };

  return (
    <SliderUI
      {...mergedProps}
      ref={ref}
    />
  );
});

Slider.displayName = 'Slider';

export default Slider;

import { Range } from '@radix-ui/react-slider';
import { cn } from '@/lib/utils';
import { sliderVariants } from './slider-variants';
import type { SliderRangeProps } from './types';

const SliderRange = (props: SliderRangeProps) => {
  const { className, color, ...rest } = props;

  const { range } = sliderVariants({ color });

  const mergedCls = cn(range(), className);

  return (
    <Range
      className={mergedCls}
      data-color={color}
      data-slot="slider-range"
      {...rest}
    />
  );
};

export default SliderRange;

import type { ComponentRef } from 'react';
import { forwardRef } from 'react';
import { Root } from '@radix-ui/react-slider';
import { cn } from '@/lib/utils';
import { sliderVariants } from './slider-variants';
import type { SliderRootProps } from './types';

const SliderRoot = forwardRef<ComponentRef<typeof Root>, SliderRootProps>((props, ref) => {
  const { className, size, ...rest } = props;

  const { root } = sliderVariants({ size });

  const mergedCls = cn(root(), className);

  return (
    <Root
      className={mergedCls}
      data-slot="slider-root"
      ref={ref}
      {...rest}
    />
  );
});

SliderRoot.displayName = 'SliderRoot';

export default SliderRoot;

import { Thumb } from '@radix-ui/react-slider';
import { cn } from '@/lib/utils';
import { sliderVariants } from './slider-variants';
import type { SliderThumbProps } from './types';

export const SliderThumb = (props: SliderThumbProps) => {
  const { className, color, size, ...rest } = props;

  const { thumb } = sliderVariants({ color, size });

  const mergedCls = cn(thumb(), className);

  return (
    <Thumb
      className={mergedCls}
      data-color={color}
      data-slot="slider-thumb"
      {...rest}
    />
  );
};

export default SliderThumb;

import { Track } from '@radix-ui/react-slider';
import { cn } from '@/lib/utils';
import { sliderVariants } from './slider-variants';
import type { SliderTrackProps } from './types';

const SliderTrack = (props: SliderTrackProps) => {
  const { className, color, size, ...rest } = props;

  const { track } = sliderVariants({ color, size });

  const mergedCls = cn(track(), className);

  return (
    <Track
      className={mergedCls}
      data-color={color}
      data-slot="slider-track"
      {...rest}
    />
  );
};

export default SliderTrack;

import type { ComponentRef } from 'react';
import { forwardRef } from 'react';
import SliderRange from './SliderRange';
import SliderRoot from './SliderRoot';
import SliderThumb from './SliderThumb';
import SliderTrack from './SliderTrack';
import type { SliderProps } from './types';

const SliderUI = forwardRef<ComponentRef<typeof SliderRoot>, SliderProps>((props, ref) => {
  const { className, classNames, color, defaultValue, size, value, trackProps, rangeProps, thumbProps, ...rest } = props;

  return (
    <SliderRoot
      className={className || classNames?.root}
      defaultValue={defaultValue}
      ref={ref}
      size={size}
      value={value}
      {...rest}
    >
      <SliderTrack
        className={classNames?.track}
        color={color}
        size={size}
        {...trackProps}
      >
        <SliderRange
          className={classNames?.range}
          color={color}
          {...rangeProps}
        />
      </SliderTrack>

      {(defaultValue || value)?.map((_, index) => (
        <SliderThumb
          className={classNames?.thumb}
          color={color}
          key={String(index)}
          size={size}
          {...thumbProps}
        />
      ))}
    </SliderRoot>
  );
});

SliderUI.displayName = 'SliderUI';

export default SliderUI;

export { default as Slider } from './Slider';

export { default as SliderRange } from './SliderRange';
export { default as SliderRoot } from './SliderRoot';
export { default as SliderThumb } from './SliderThumb';
export { default as SliderTrack } from './SliderTrack';

export * from './types';

import { tv } from 'tailwind-variants';

export const sliderVariants = tv({
  defaultVariants: {
    color: 'primary',
    size: 'md'
  },
  slots: {
    range: `absolute h-full data-[orientation=vertical]:w-full`,
    root: [
      `relative flex w-full touch-none select-none items-center`,
      `data-[orientation=vertical]:flex-col data-[orientation=vertical]:h-full`
    ],
    thumb: [
      `block rounded-full bg-background transition-colors duration-200`,
      `focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-offset-background`,
      `disabled:cursor-not-allowed disabled:opacity-50`
    ],
    track: `relative w-full grow overflow-hidden rounded-full`
  },
  variants: {
    color: {
      accent: {
        range: 'bg-accent-foreground',
        thumb: 'border-accent-foreground focus-visible:ring-accent-foreground',
        track: 'bg-accent-foreground/20'
      },
      carbon: {
        range: 'bg-carbon',
        thumb: 'border-carbon focus-visible:ring-carbon',
        track: 'bg-carbon/20'
      },
      destructive: {
        range: 'bg-destructive',
        thumb: 'border-destructive focus-visible:ring-destructive',
        track: 'bg-destructive/20'
      },
      info: {
        range: 'bg-info',
        thumb: 'border-info focus-visible:ring-info',
        track: 'bg-info/20'
      },
      primary: {
        range: 'bg-primary',
        thumb: 'border-primary focus-visible:ring-primary',
        track: 'bg-primary/20'
      },
      secondary: {
        range: 'bg-secondary-foreground',
        thumb: 'border-secondary-foreground focus-visible:ring-secondary-foreground',
        track: 'bg-secondary-foreground/20'
      },
      success: {
        range: 'bg-success',
        thumb: 'border-success focus-visible:ring-success',
        track: 'bg-success/20'
      },
      warning: {
        range: 'bg-warning',
        thumb: 'border-warning focus-visible:ring-warning',
        track: 'bg-warning/20'
      }
    },
    size: {
      '2xl': {
        root: 'data-[orientation=vertical]:w-3.5',
        thumb: 'size-7 border-[3.5px]',
        track: 'h-3.5 data-[orientation=vertical]:w-3.5'
      },
      'lg': {
        root: 'data-[orientation=vertical]:w-2.5',
        thumb: 'size-5.5 border-[2.5px]',
        track: 'h-2.5 data-[orientation=vertical]:w-2.5'
      },
      'md': {
        root: 'data-[orientation=vertical]:w-2',
        thumb: 'size-5 border-2',
        track: 'h-2 data-[orientation=vertical]:w-2'
      },
      'sm': {
        root: 'data-[orientation=vertical]:w-1.5',
        thumb: 'size-4.5 border-[1.75px]',
        track: 'h-1.5 data-[orientation=vertical]:w-1.5'
      },
      'xl': {
        root: 'data-[orientation=vertical]:w-3',
        thumb: 'size-6 border-3',
        track: 'h-3 data-[orientation=vertical]:w-3'
      },
      'xs': {
        root: 'data-[orientation=vertical]:w-1.25',
        thumb: 'size-4 border-[1.5px]',
        track: 'h-1.25 data-[orientation=vertical]:w-1.25'
      }
    }
  }
});

export type SliderSlots = keyof typeof sliderVariants.slots;

import type {
  SliderProps as _SliderProps,
  SliderRangeProps as _SliderRangeProps,
  SliderThumbProps as _SliderThumbProps,
  SliderTrackProps as _SliderTrackProps
} from '@radix-ui/react-slider';
import type { StyledComponentProps, ClassValue, ThemeColor } from '@/types/shared';
import type { SliderSlots } from './slider-variants';

/**
 * Props for the slider range component.
 * The filled portion of the slider track between the minimum and maximum values.
 */
export interface SliderRangeProps extends StyledComponentProps<_SliderRangeProps> {
  /**
   * Theme color for the slider range fill.
   * Determines the color of the filled portion of the slider.
   */
  color?: ThemeColor;
}

/**
 * Props for the slider root component.
 * The main container for all slider elements including track, range, and thumbs.
 */
export interface SliderRootProps extends StyledComponentProps<_SliderProps> {}

/**
 * Props for the slider thumb component.
 * The draggable handle that the user moves to change the slider value.
 */
export interface SliderThumbProps extends StyledComponentProps<_SliderThumbProps> {
  /**
   * Theme color for the slider thumb.
   * Determines the appearance of the draggable handle.
   */
  color?: ThemeColor;
}

/**
 * Props for the slider track component.
 * The background rail on which the range fill and thumb sit.
 */
export interface SliderTrackProps extends StyledComponentProps<_SliderTrackProps> {
  /**
   * Theme color for the slider track.
   * Determines the background color of the slider rail.
   */
  color?: ThemeColor;
}

/**
 * Class names for different slots in the slider component.
 * Allows customizing styles for track, range, and thumb elements.
 */
export type SliderClassNames = Partial<Record<SliderSlots, ClassValue>>;

/**
 * Props for the main Slider component.
 * A range input component for selecting a value or range of values on a continuous scale.
 *
 * @example
 * ```tsx
 * // Single value slider
 * <Slider
 *   defaultValue={[50]}
 *   min={0}
 *   max={100}
 *   step={1}
 *   color="primary"
 * />
 *
 * // Range slider
 * <Slider
 *   defaultValue={[25, 75]}
 *   min={0}
 *   max={100}
 *   step={5}
 *   color="secondary"
 * />
 * ```
 */
export interface SliderProps extends Omit<SliderRootProps, 'children'> {
  /**
   * Class names for customizing different parts of the slider component.
   */
  classNames?: SliderClassNames;
  /**
   * Theme color applied to the slider range and thumb.
   * Affects both the fill and interactive elements.
   */
  color?: ThemeColor;
  /**
   * Props for the slider track component.
   */
  trackProps?: SliderTrackProps;
  /**
   * Props for the slider range component.
   */
  rangeProps?: SliderRangeProps;
  /**
   * Props for the slider thumb component.
   */
  thumbProps?: SliderThumbProps;
}
